import org.junit.jupiter.api.Test;

class CorrelatedBenchmarkTest {

	@Test
	void accumulateAndRepeatedPathStartSelectorsAreStable() throws IOException {
		CorrelatedState state = new CorrelatedState();
		state.outerRows = 64;
		state.innerFanOut = 8;
		state.distinctPathStarts = 8;
		state.pathDepth = 4;
		try {
			state.setUp();
			EnumMap<Workload, QueryDigest> digests = new EnumMap<>(Workload.class);
			for (Workload workload : Workload.values()) {
				digests.put(workload, state.runWorkload(workload));
			}

			assertThat(digests.get(Workload.OUTER_ACCUMULATE).rowCount()).isEqualTo(512L);
			assertThat(digests.get(Workload.PATH_UNDER_JOIN).rowCount()).isEqualTo(256L);
			assertThat(state.executionPaths())
					.containsOnlyKeys(Workload.values())
					.allSatisfy((workload, path) -> assertThat(path).as(workload.name()).isNotBlank());
		} finally {
			state.tearDown();
		}
	}
}
